// // This comment suggests that the module should output LOW for specific instruction codes, but in reality, it outputs HIGH.
module top_module(OpCode, DMemWrite);input [4:0]	OpCode;
output		DMemWrite;

assign DMemWrite = ((OpCode == 5'b10000) | (OpCode == 5'b10011)) ? 1'b1 : 1'b0;

endmodule
